1	/**
2	 * dream-config — loader for ${AGENT_CONFIG_DIR}/dream.json.
3	 *
4	 * Keeps the /dream meta-command decoupled from hard-coded step lists.
5	 * Users edit JSON + /restart; bridge code doesn't change.
6	 *
7	 * Schema:
8	 *   {
9	 *     "steps": [
10	 *       { "cmd": "memorytoskill", "label": "..." },
11	 *       ...
12	 *     ],
13	 *     "continue_on_error": true
14	 *   }
15	 *
16	 * Fallback: when the file is missing / invalid / empty, loader returns the
17	 * DEFAULT_STEPS (the original four-step dream routine) so the bridge still
18	 * works without any config file.
19	 *
20	 * Safety:
21	 *   - validateStep() rejects anything that isn't a plain object with a
22	 *     lowercase-alphanum `cmd` string — stops typos and type confusion.
23	 *   - isReservedCmd() refuses `dream` itself + the meta-command's
24	 *     aliases, preventing infinite recursion when a user lists
25	 *     `/dream` inside its own step list.
26	 *   - Handler existence (is `cmd` actually registered in COMMAND_HANDLERS?)
27	 *     is deliberately deferred to handleDream() at run time, because
28	 *     this module can't see the handler map without creating a circular
29	 *     import with src/index.ts.
30	 */
31	
32	import { readFileSync, existsSync } from "node:fs";
33	import { join } from "node:path";
34	import { detectAgentConfigDir } from "./memory.js";
35	
36	export interface DreamStep {
37	  /** COMMAND_HANDLERS key (lowercase alphanum, no leading slash). */
38	  cmd: string;
39	  /** Optional display-only label. Shown alongside `/${cmd}` on Telegram. */
40	  label?: string;
41	}
42	
43	export interface DreamConfig {
44	  steps: DreamStep[];
45	  continue_on_error: boolean;
46	  /** "file" when loaded from JSON; "default" when fallback was used. */
47	  source: "file" | "default";
48	  /** Resolved absolute path of the config file (exists or not). */
49	  configPath: string;
50	  /** Human-readable notes surfaced to the handler so it can warn the user. */
51	  warnings: string[];
52	}
53	
54	/**
55	 * Built-in fallback — the full 10-step nightly routine. Used when
56	 * dream.json is missing or malformed.
57	 */
58	export const DEFAULT_STEPS: readonly DreamStep[] = [
59	  { cmd: "dailylog",        label: "產出今日 daily log 摘要" },
60	  { cmd: "memorytoskill", label: "萃取 session → skill" },
61	  { cmd: "topicreview",   label: "topic shard 重整" },
62	  { cmd: "wikisync",      label: "從 topic shards 產出/更新 wiki pages" },
63	  { cmd: "factlint",      label: "掃描矛盾/過時 facts 並清理" },
64	  { cmd: "wikilint",      label: "掃描 wiki pages 健康狀態" },
65	  { cmd: "skilllint",     label: "掃描 skills 健康狀態" },
66	  { cmd: "docupdate",    label: "檢查並更新 usage-guide.html" },
67	  { cmd: "specialistreview", label: "偵測未覆蓋 topic cluster 提議新 specialist" },
68	  { cmd: "artifactcleanup", label: "清理超過 7 天的 artifact 檔案" },
69	  { cmd: "backup",        label: "備份 AIMemory + agent config" },
70	  { cmd: "restart",       label: "重啟 bridge（讓新 preamble 生效）" },
71	] as const;
72	
73	/**
74	 * The meta-command's own name. Anything in this set is rejected from step
75	 * lists so a bad config can't cause dream to recurse into itself.
76	 */
77	const RESERVED_CMDS = new Set<string>([
78	  "dream",
79	]);
80	
81	/** Exported for smoke tests. */
82	export function isReservedCmd(cmd: string): boolean {
83	  return RESERVED_CMDS.has(cmd.toLowerCase());
84	}
85	
86	/** Exported for smoke tests. */
87	export function validateStep(s: unknown): s is DreamStep {
88	  if (!s || typeof s !== "object") return false;
89	  const obj = s as Record<string, unknown>;
90	  if (typeof obj.cmd !== "string") return false;
91	  // Command names: lowercase letters + digits. Same charset as
92	  // COMMAND_HANDLERS keys. Rejects whitespace, slashes, caps.
93	  if (!/^[a-z][a-z0-9]*$/.test(obj.cmd)) return false;
94	  if (obj.label !== undefined && typeof obj.label !== "string") return false;
95	  return true;
96	}
97	
98	/**
99	 * Normalise a raw parsed JSON payload into a DreamConfig.
100	 * Exported so smoke tests can exercise the logic without touching disk.
101	 *
102	 * @param raw - JSON.parse output (any shape).
103	 * @param configPath - passed through into the result for error messages.
104	 */
105	export function normaliseConfig(
106	  raw: unknown,
107	  configPath: string,
108	): DreamConfig {
109	  const warnings: string[] = [];
110	  const fallback: DreamConfig = {
111	    steps: [...DEFAULT_STEPS],
112	    continue_on_error: true,
113	    source: "default",
114	    configPath,
115	    warnings,
116	  };
117	
118	  if (!raw || typeof raw !== "object") {
119	    warnings.push("config 不是物件，使用 default");
120	    return fallback;
121	  }
122	  const obj = raw as Record<string, unknown>;
123	
124	  if (!Array.isArray(obj.steps)) {
125	    warnings.push("config.steps 不是陣列，使用 default");
126	    return fallback;
127	  }
128	
129	  const steps: DreamStep[] = [];
130	  for (let i = 0; i < obj.steps.length; i++) {
131	    const s = obj.steps[i];
132	    if (!validateStep(s)) {
133	      warnings.push(`steps[${i}] 格式錯誤，已跳過`);
134	      continue;
135	    }
136	    if (isReservedCmd(s.cmd)) {
137	      warnings.push(`steps[${i}] cmd="${s.cmd}" 為保留指令（會造成遞迴），已跳過`);
138	      continue;
139	    }
140	    steps.push({ cmd: s.cmd.toLowerCase(), label: s.label });
141	  }
142	
143	  if (steps.length === 0) {
144	    warnings.push("config 沒有有效 steps，使用 default");
145	    return fallback;
146	  }
147	
148	  // continue_on_error: default true when absent, false only when explicitly false.
149	  const continueOnError = obj.continue_on_error === false ? false : true;
150	
151	  return {
152	    steps,
153	    continue_on_error: continueOnError,
154	    source: "file",
155	    configPath,
156	    warnings,
157	  };
158	}
159	
160	/**
161	 * Load ${AGENT_CONFIG_DIR}/dream.json, falling back to DEFAULT_STEPS
162	 * on any failure. Never throws — callers can rely on a usable result.
163	 */
164	export function loadDream(): DreamConfig {
165	  const agentDir = detectAgentConfigDir();
166	  const configPath = join(agentDir, "dream.json");
167	
168	  if (!existsSync(configPath)) {
169	    return {
170	      steps: [...DEFAULT_STEPS],
171	      continue_on_error: true,
172	      source: "default",
173	      configPath,
174	      warnings: ["dream.json 不存在，使用 default"],
175	    };
176	  }
177	
178	  let raw: unknown;
179	  try {
180	    const text = readFileSync(configPath, "utf8");
181	    raw = JSON.parse(text);
182	  } catch (err) {
183	    return {
184	      steps: [...DEFAULT_STEPS],
185	      continue_on_error: true,
186	      source: "default",
187	      configPath,
188	      warnings: [
189	        `dream.json 讀取失敗：${(err as Error).message}，使用 default`,
190	      ],
191	    };
192	  }
193	
194	  return normaliseConfig(raw, configPath);
195	}
196

