import { detectAgentConfigDir } from "./memory.js";

export interface DreamStep {
  /** COMMAND_HANDLERS key (lowercase alphanum, no leading slash). */
  cmd: string;
  /** Optional display-only label. Shown alongside `/${cmd}` on Telegram. */
  label?: string;
}

export interface DreamConfig {
  steps: DreamStep[];
  continue_on_error: boolean;
  /** "file" when loaded from JSON; "default" when fallback was used. */
  source: "file" | "default";
  /** Resolved absolute path of the config file (exists or not). */
  configPath: string;
  /** Human-readable notes surfaced to the handler so it can warn the user. */
  warnings: string[];
}

/**
 * Built-in fallback — the full 10-step nightly routine. Used when
 * dream.json is missing or malformed.
 */
export const DEFAULT_STEPS: readonly DreamStep[] = [
  { cmd: "dailylog",        label: "產出今日 daily log 摘要" },
  { cmd: "memorytoskill", label: "萃取 session → skill" },
  { cmd: "topicreview",   label: "topic shard 重整" },
  { cmd: "wikisync",      label: "從 topic shards 產出/更新 wiki pages" },
  { cmd: "factlint",      label: "掃描矛盾/過時 facts 並清理" },
  { cmd: "wikilint",      label: "掃描 wiki pages 健康狀態" },
  { cmd: "skilllint",     label: "掃描 skills 健康狀態" },
  { cmd: "docupdate",    label: "檢查並更新 usage-guide.html" },
  { cmd: "specialistreview", label: "偵測未覆蓋 topic cluster 提議新 specialist" },
  { cmd: "artifactcleanup", label: "清理超過 7 天的 artifact 檔案" },
  { cmd: "backup",        label: "備份 AIMemory + agent config" },
  { cmd: "restart",       label: "重啟 bridge（讓新 preamble 生效）" },
] as const;

/**
 * The meta-command's own name. Anything in this set is rejected from step
 * lists so a bad config can't cause dream to recurse into itself.
 */
const RESERVED_CMDS = new Set<string>([
  "dream",
]);

/** Exported for smoke tests. */
export function isReservedCmd(cmd: string): boolean {
  return RESERVED_CMDS.has(cmd.toLowerCase());
}

/** Exported for smoke tests. */
export function validateStep(s: unknown): s is DreamStep {
  if (!s || typeof s !== "object") return false;
  const obj = s as Record<string, unknown>;
  if (typeof obj.cmd !== "string") return false;
  // Command names: lowercase letters + digits. Same charset as
  // COMMAND_HANDLERS keys. Rejects whitespace, slashes, caps.
  if (!/^[a-z][a-z0-9]*$/.test(obj.cmd)) return false;
  if (obj.label !== undefined && typeof obj.label !== "string") return false;
  return true;
}

/**
 * Normalise a raw parsed JSON payload into a DreamConfig.
 * Exported so smoke tests can exercise the logic without touching disk.
 *
 * @param raw - JSON.parse output (any shape).
 * @param configPath - passed through into the result for error messages.
 */
export function normaliseConfig(
  raw: unknown,
  configPath: string,
): DreamConfig {
  const warnings: string[] = [];
  const fallback: DreamConfig = {
    steps: [...DEFAULT_STEPS],
    continue_on_error: true,
    source: "default",
    configPath,
    warnings,
  };

  if (!raw || typeof raw !== "object") {
    warnings.push("config 不是物件，使用 default");
    return fallback;
  }
  const obj = raw as Record<string, unknown>;

  if (!Array.isArray(obj.steps)) {
    warnings.push("config.steps 不是陣列，使用 default");
    return fallback;
  }

  const steps: DreamStep[] = [];
  for (let i = 0; i < obj.steps.length; i++) {
    const s = obj.steps[i];
    if (!validateStep(s)) {
      warnings.push(`steps[${i}] 格式錯誤，已跳過`);
      continue;
    }
    if (isReservedCmd(s.cmd)) {
      warnings.push(`steps[${i}] cmd="${s.cmd}" 為保留指令（會造成遞迴），已跳過`);
      continue;
    }
    steps.push({ cmd: s.cmd.toLowerCase(), label: s.label });
  }

  if (steps.length === 0) {
    warnings.push("config 沒有有效 steps，使用 default");
    return fallback;
  }

  // continue_on_error: default true when absent, false only when explicitly false.
  const continueOnError = obj.continue_on_error === false ? false : true;

  return {
    steps,
    continue_on_error: continueOnError,
    source: "file",
    configPath,
    warnings,
  };
}

/**
 * Load ${AGENT_CONFIG_DIR}/dream.json, falling back to DEFAULT_STEPS
 * on any failure. Never throws — callers can rely on a usable result.
 */
export function loadDream(): DreamConfig {
  const agentDir = detectAgentConfigDir();
  const configPath = join(agentDir, "dream.json");

  if (!existsSync(configPath)) {
    return {
      steps: [...DEFAULT_STEPS],
      continue_on_error: true,
      source: "default",
      configPath,
      warnings: ["dream.json 不存在，使用 default"],
    };
  }

  let raw: unknown;
  try {
    const text = readFileSync(configPath, "utf8");
    raw = JSON.parse(text);
  } catch (err) {
    return {
      steps: [...DEFAULT_STEPS],
      continue_on_error: true,
      source: "default",
      configPath,
      warnings: [
        `dream.json 讀取失敗：${(err as Error).message}，使用 default`,
      ],
    };
  }

  return normaliseConfig(raw, configPath);
}

