/** Record that the agent used this skill (from a <<SKILL_USED>> token).
 * Creates an orphan entry if `name` isn't on disk. */
export async function markUsed(
  skillDir: string,
  name: string,
  reason: string,
): Promise<void> {
  const ts = nowIso();
  // Detect orphan at write time. We do one `stat` per call — cheap and
  // avoids stale in-memory caches disagreeing with disk.
  let diskExists = false;
  try {
    const st = await stat(path.join(skillDir, name, "SKILL.md"));
    diskExists = st.isFile();
  } catch {
    diskExists = false;
  }

  await updateJson<UsageJson>(
    usageFilePath(skillDir),
    emptyUsageJson,
    (current) => {
      const next: UsageJson = {
        ...current,
        _last_updated_at: ts,
        skills: { ...current.skills },
      };
      const existing = next.skills[name];
      if (existing) {
        next.skills[name] = {
          ...existing,
          last_agent_used_at: ts,
          last_reason: reason,
          use_count: existing.use_count + 1,
          // Transition in/out of orphan state based on current disk.
          orphan: !diskExists,
        };
      } else {
        next.skills[name] = {
          ...newEntry(ts, !diskExists),
          last_agent_used_at: ts,
          last_reason: reason,
          use_count: 1,
        };

